 77→#[instrument(skip(state), fields(life.session_id = %session_id))]
 78→async fn get_projection(
 79→    State(state): State<AppState>,
 80→    Path(session_id): Path<String>,
 81→) -> Json<ProjectionResponse> {
 82→    let projections = state.projections.read().await;
 83→
 84→    let (homeostatic_state, found) = match projections.get(&session_id) {
 85→        Some(s) => (s.clone(), true),
 86→        None => (HomeostaticState::for_agent(&session_id), false),
 87→    };
